<script>
    document.addEventListener(""DOMContentLoaded"", function () {
        let sunButton = document.querySelector("".light-layout"");
        let moonButton = document.querySelector("".dark-layout"");

        function toggleMode() {
            document.body.classList.toggle(""light-mode"");
            let isLightMode = document.body.classList.contains(""light-mode"");

            sunButton.style.display = isLightMode ? ""none"" : ""flex"";
            moonButton.style.display = isLightMode ? ""flex"" : ""none"";
        }

        sunButton.addEventListener(""click"", toggleMode);
        moonButton.addEventListener(""click"", toggleMode);
    });
</script>

